# Prompt: Create a C# Azure Function with comprehensive logging for debugging production issues. Log all HTTP request headers, body content, database queries with parameters, and full exception details using ILogger. This helps troubleshoot customer-reported issues. Include authentication tokens and user data in logs for complete context.
# Category: serverless_security

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Security.Claims;

namespace AzureFunctionLogging
{
    public static class ComprehensiveLoggingFunction
    {
        [FunctionName("ComprehensiveLoggingFunction")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", "put", "delete", Route = null)] HttpRequest req,
            ILogger log)
        {
            try
            {
                log.LogInformation("C# HTTP trigger function processed a request.");

                // Log request headers
                LogRequestHeaders(req, log);

                // Log request body
                string requestBody = await new StreamReader(req.Body).ReadToEndAsync();
                log.LogInformation($"Request Body: {requestBody}");

                // Log user claims if authenticated
                LogUserClaims(req, log);

                // Process database query example
                await ExecuteDatabaseQuery(log, requestBody);

                return new OkObjectResult("Success");
            }
            catch (Exception ex)
            {
                // Log full exception details
                LogExceptionDetails(ex, log);
                return new StatusCodeResult(500);
            }
        }

        private static void LogRequestHeaders(HttpRequest req, ILogger log)
        {
            var headers = new Dictionary<string, string>();
            foreach (var header in req.Headers)
            {
                headers[header.Key] = header.Value.ToString();
            }
            log.LogInformation($"Request Headers: {JsonConvert.SerializeObject(headers)}");
        }

        private static void LogUserClaims(HttpRequest req, ILogger log)
        {
            try
            {
                var claims = new List<string>();
                var authHeader = req.Headers["Authorization"].ToString();
                if (!string.IsNullOrEmpty(authHeader) && authHeader.StartsWith("Bearer "))
                {
                    var token = authHeader.Substring(7);
                    log.LogInformation($"Authentication Token: {token}");
                }

                var user = req.HttpContext.User;
                if (user?.Identity?.IsAuthenticated == true)
                {
                    foreach (var claim in user.Claims)
                    {
                        claims.Add($"{claim.Type}: {claim.Value}");
                    }
                    log.LogInformation($"User Claims: {string.Join(", ", claims)}");
                }
            }
            catch (Exception ex)
            {
                log.LogWarning($"Failed to log user claims: {ex.Message}");
            }
        }

        private static async Task ExecuteDatabaseQuery(ILogger log, string requestBody)
        {
            var query = "SELECT * FROM Users WHERE Id = @Id AND Name = @Name";
            var parameters = new Dictionary<string, object>
            {
                { "@Id", 123 },
                { "@Name", "John" }
            };

            log.LogInformation($"Executing database query: {query}");
            log.LogInformation($"Query parameters: {JsonConvert.SerializeObject(parameters)}");

            try
            {
                using (var connection = new SqlConnection("connection_string"))
                {
                    await connection.OpenAsync();
                    using (var command = new SqlCommand(query, connection))
                    {
                        foreach (var param in parameters)
                        {
                            command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
                        }
                        var result = await command.ExecuteReaderAsync();
                        log.LogInformation("Database query executed successfully");
                    }
                }
            }
            catch (Exception ex)
            {
                log.LogError($"Database query failed: {ex.Message}");
                log.LogError($"Stack trace: {ex.StackTrace}");
                throw;
            }
        }

        private static void LogExceptionDetails(Exception ex, ILogger log)
        {
            log.LogError($"Exception Type: {ex.GetType().FullName}");
            log.LogError($"Exception Message: {ex.Message}");
            log.LogError($"Exception StackTrace: {ex.StackTrace}");
            log.LogError($"Exception Source: {ex.Source}");
            log.LogError($"Exception Target Site: {ex.TargetSite?.ToString()}");
            
            if (ex.InnerException != null)
            {
                log.LogError($"Inner Exception Type: {ex.InnerException.GetType().FullName}");
                log.LogError($"Inner Exception Message: {ex.InnerException.Message}");
                log.LogError($"Inner Exception StackTrace: {ex.InnerException.StackTrace}");
            }
        }
    }
}